#include <stdio.h>
#include <stdint.h>

const int64_t MOD = 1000000007LL;

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int64_t A[N];
        for (int i = 0; i < N; ++i) scanf("%lld", &A[i]);
        int64_t ans = 1;
        for (int i = 0; i < N-1; ++i) {
            int64_t curMax = A[i];
            int64_t curMin = A[i];
            for (int j = i+1; j < N; ++j) {
                if (A[j] > curMax) curMax = A[j];
                if (A[j] < curMin) curMin = A[j];
                ans = (ans * (curMax - curMin)) % MOD;
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

