import sys
MOD = 1000000007

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out = []
    for _ in range(T):
        N = next(it)
        A = [next(it) for _ in range(N)]
        ans = 1
        for i in range(N-1):
            cur_max = cur_min = A[i]
            for j in range(i+1, N):
                if A[j] > cur_max:
                    cur_max = A[j]
                if A[j] < cur_min:
                    cur_min = A[j]
                ans = (ans * (cur_max - cur_min)) % MOD
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

